@* Summary statistics bar at the top of the board *@

<div class="board-stats d-flex gap-3 flex-wrap">
    <span class="badge bg-primary">Total: @Total</span>
    <span class="badge bg-info">To Do: @ToDo</span>
    <span class="badge bg-warning text-dark">In Progress: @InProgress</span>
    <span class="badge bg-success">Done: @Done</span>
    <span class="badge bg-danger">Overdue: @Overdue</span>
</div>

@code {
    [Parameter] public int Total { get; set; }
    [Parameter] public int ToDo { get; set; }
    [Parameter] public int InProgress { get; set; }
    [Parameter] public int Done { get; set; }
    [Parameter] public int Overdue { get; set; }
}

@* Displays a single task as a card with move buttons *@

<div class="task-card">
    <div class="task-card-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    </div>
    <div class="task-card-body">
        <span class="task-assignee">@Task.Assignee</span>
        <span class="task-due">@Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-card-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn btn-sm btn-outline-secondary" @onclick="OnMoveLeftClick">← Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn btn-sm btn-outline-secondary" @onclick="OnMoveRightClick">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveRight { get; set; }

    private async System.Threading.Tasks.Task OnMoveLeftClick() => await OnMoveLeft.InvokeAsync(Task);
    private async System.Threading.Tasks.Task OnMoveRightClick() => await OnMoveRight.InvokeAsync(Task);
}

@* Inline form for creating a new task within a column *@

@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm add-task-btn" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="add-task-form">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-2">
            <button class="btn btn-primary btn-sm" @onclick="Save">Save</button>
            <button class="btn btn-secondary btn-sm" @onclick="Cancel">Cancel</button>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired]
    public string Status { get; set; } = default!;

    [Parameter]
    public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool IsVisible;
    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        ResetForm();
        IsVisible = false;
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title))
            return;

        // Create a temporary TaskItem to pass to the parent; the parent calls the service
        var newTask = new TaskItem(0, title.Trim(), assignee.Trim(), priority, dueDate, Status);
        await OnTaskCreated.InvokeAsync(newTask);
        ResetForm();
        IsVisible = false;
    }

    private void ResetForm()
    {
        title = "";
        assignee = "";
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
    }
}

