@* A single Kanban column with header, task cards, and add-task form *@

<div class="kanban-column">
    <div class="kanban-column-header">
        <h5>@Title <span class="badge bg-secondary">@Tasks.Count</span></h5>
    </div>
    <div class="kanban-column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="OnMoveLeft"
                      OnMoveRight="OnMoveRight" />
        }
    </div>
    <div class="kanban-column-footer">
        <AddTaskForm Status="@Status" OnTaskCreated="OnTaskCreated" />
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string Title { get; set; } = default!;

    [Parameter, EditorRequired]
    public string Status { get; set; } = default!;

    [Parameter]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveRight { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnTaskCreated { get; set; }
}

@* Search bar for filtering tasks by title *@

<div class="board-search mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="OnInput" />
</div>

@code {
    [Parameter]
    public string SearchTerm { get; set; } = "";

    [Parameter]
    public EventCallback<string> SearchTermChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        await SearchTermChanged.InvokeAsync(value);
    }
}

arguments.file_text:
@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (isLoading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <BoardStats Total="allTasks.Count"
                ToDo="CountByStatus("To Do")"
                InProgress="CountByStatus("In Progress")"
                Done="CountByStatus("Done")"
                Overdue="allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <BoardSearchBar SearchTerm="@searchTerm" SearchTermChanged="OnSearchChanged" />

    <div class="kanban-board">
        <KanbanColumn Title="To Do" Status="To Do"
                      Tasks="GetFilteredTasks("To Do")"
                      ShowMoveLeft="false" ShowMoveRight="true"
                      OnMoveRight="@(t => MoveTask(t, "In Progress"))"
                      OnTaskCreated="CreateTask" />

        <KanbanColumn Title="In Progress" Status="In Progress"
                      Tasks="GetFilteredTasks("In Progress")"
                      ShowMoveLeft="true" ShowMoveRight="true"
                      OnMoveLeft="@(t => MoveTask(t, "To Do"))"
                      OnMoveRight="@(t => MoveTask(t, "Done"))"
                      OnTaskCreated="CreateTask" />

        <KanbanColumn Title="Done" Status="Done"
                      Tasks="GetFilteredTasks("Done")"
                      ShowMoveLeft="true" ShowMoveRight="false"
                      OnMoveLeft="@(t => MoveTask(t, "In Progress"))"
                      OnTaskCreated="CreateTask" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private int CountByStatus(string status) =>
        allTasks.Count(t => t.Status == status);

    private List<TaskItem> GetFilteredTasks(string status) =>
        allTasks
            .Where(t => t.Status == status)
            .Where(t => string.IsNullOrWhiteSpace(searchTerm)
                        || t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase))
            .ToList();

    private void OnSearchChanged(string value) => searchTerm = value;

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Update local state
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
                allTasks[index] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task CreateTask(TaskItem draft)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(draft.Title, draft.Assignee, draft.Priority, draft.DueDate);
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

.kanban-board {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

.kanban-column {
    flex: 1;
    min-width: 250px;
    background: #f8f9fa;
    border-radius: 8px;
    padding: 0.75rem;
    display: flex;
    flex-direction: column;
}

.kanban-column-header h5 {
    margin: 0 0 0.5rem;
}

.kanban-column-body {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    min-height: 60px;
}

.kanban-column-footer {
    margin-top: 0.75rem;
}

.task-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.6rem;
}

.task-card-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.35rem;
}

.task-title {
    font-weight: 600;
}

.priority-badge {
    font-size: 0.75rem;
    padding: 0.15rem 0.45rem;
    border-radius: 4px;
    color: #fff;
}

.priority-high {
    background-color: #dc3545;
}

.priority-medium {
    background-color: #ffc107;
    color: #212529;
}

.priority-low {
    background-color: #198754;
}

.task-card-body {
    display: flex;
    justify-content: space-between;
    font-size: 0.85rem;
    color: #6c757d;
    margin-bottom: 0.35rem;
}

.task-card-actions {
    display: flex;
    gap: 0.35rem;
}

.add-task-btn {
    width: 100%;
}

.add-task-form {
    background: #fff;
    border: 1px dashed #adb5bd;
    border-radius: 6px;
    padding: 0.6rem;
}

.board-stats {
    margin-bottom: 1rem;
}

