toolArgs.file_text:
@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (isLoading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <BoardStats Total="allTasks.Count"
                ToDo="CountByStatus("To Do")"
                InProgress="CountByStatus("In Progress")"
                Done="CountByStatus("Done")"
                Overdue="allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <BoardSearchBar SearchTerm="@searchTerm" SearchTermChanged="OnSearchChanged" />

    <div class="kanban-board">
        <KanbanColumn Title="To Do" Status="To Do"
                      Tasks="GetFilteredTasks("To Do")"
                      ShowMoveLeft="false" ShowMoveRight="true"
                      OnMoveRight="@(t => MoveTask(t, "In Progress"))"
                      OnTaskCreated="CreateTask" />

        <KanbanColumn Title="In Progress" Status="In Progress"
                      Tasks="GetFilteredTasks("In Progress")"
                      ShowMoveLeft="true" ShowMoveRight="true"
                      OnMoveLeft="@(t => MoveTask(t, "To Do"))"
                      OnMoveRight="@(t => MoveTask(t, "Done"))"
                      OnTaskCreated="CreateTask" />

        <KanbanColumn Title="Done" Status="Done"
                      Tasks="GetFilteredTasks("Done")"
                      ShowMoveLeft="true" ShowMoveRight="false"
                      OnMoveLeft="@(t => MoveTask(t, "In Progress"))"
                      OnTaskCreated="CreateTask" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private int CountByStatus(string status) =>
        allTasks.Count(t => t.Status == status);

    private List<TaskItem> GetFilteredTasks(string status) =>
        allTasks
            .Where(t => t.Status == status)
            .Where(t => string.IsNullOrWhiteSpace(searchTerm)
                        || t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase))
            .ToList();

    private void OnSearchChanged(string value) => searchTerm = value;

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Update local state
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
                allTasks[index] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task CreateTask(TaskItem draft)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(draft.Title, draft.Assignee, draft.Priority, draft.DueDate);
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

